	-- Profile import
	Details:ImportProfile(profileString, name)

	-- Apply the profile
	if Details:GetCurrentProfileName() ~= name then
		Details:ApplyProfile(name)
	end

	-- Load the profile on all characters
	Details.always_use_profile = true
	Details.always_use_profile_name = name

	if installer then
		_G.LuckyoneInstallStepComplete:ShowMessage(L["Details profile has been set."])
	end

	Private:Print(L["Details profile has been set."])
end
